<?php namespace Database\Seeders; use App\Models\Church; use App\Models\Permission; use App\Models\Role; use App\Models\User; use Illuminate\Database\Seeder; use Illuminate\Support\Facades\Hash; class RolesAndPermissionsSeeder extends Seeder { public function run(): void { Permission::createDefaultPermissions(); $customPermissions = [ ['name' => 'View Worker Attendance', 'slug' => 'attendance.view_worker', 'description' => 'Ability to view worker specific attendance records', 'module' => Permission::MODULE_ATTENDANCE, 'is_active' => true], ['name' => 'Manage Counselling Bookings', 'slug' => 'counselling.manage', 'description' => 'Ability to manage counselling bookings (PA)', 'module' => 'counselling', 'is_active' => true] ]; foreach ($customPermissions as $permission) { Permission::firstOrCreate(['slug' => $permission['slug']], $permission); } Role::createDefaultRoles(); $phase2Roles = [ 'curate_pastor' => [ 'name' => 'Curate Pastor', 'level' => 85, 'description' => 'Second in command, manages workers' ], 'attendance_manager' => [ 'name' => 'Attendance Manager', 'level' => 75, 'description' => 'Manages church service attendance' ], 'pa' => [ 'name' => 'Personal Assistant', 'level' => 70, 'description' => 'PA to Head Pastor, manages bookings' ] ]; foreach ($phase2Roles as $slug => $roleData) { Role::firstOrCreate(['slug' => $slug], ['name' => $roleData['name'], 'description' => $roleData['description'], 'level' => $roleData['level'], 'is_active' => true]); } Permission::assignDefaultPermissions(); $curatePastor = Role::findBySlug('curate_pastor'); if ($curatePastor) { $basePastorPermissions = Permission::whereIn('module', [Permission::MODULE_MEMBER, Permission::MODULE_COMMUNICATION, Permission::MODULE_ATTENDANCE])->orWhere('slug', 'dashboard.access')->orWhere('slug', 'attendance.view_worker')->get(); $curatePastor->permissions()->sync($basePastorPermissions); } $attendanceManager = Role::findBySlug('attendance_manager'); if ($attendanceManager) { $attendancePermissions = Permission::where('module', Permission::MODULE_ATTENDANCE)->where('slug', '!=', 'attendance.view_worker')->orWhere('slug', 'dashboard.access')->get(); $attendanceManager->permissions()->sync($attendancePermissions); } $pa = Role::findBySlug('pa'); if ($pa) { $paPermissions = Permission::where('slug', 'counselling.manage')->orWhere('slug', 'dashboard.access')->orWhere('module', Permission::MODULE_COMMUNICATION)->get(); $pa->permissions()->sync($paPermissions); } $adultChurch = Church::where('name', 'Adult Church')->first(); $youthChurch = Church::where('name', 'Youth Church')->first(); if ($adultChurch) { $adultAdmin = User::firstOrCreate(['email' => 'adult_admin@church.com'], ['name' => 'Adult Church Admin', 'password' => Hash::make('password123'), 'role' => 'admin', 'church_id' => $adultChurch->id]); $adultAdmin->roles()->sync([Role::findBySlug(Role::ADMIN)->id]); } if ($youthChurch) { $youthAdmin = User::firstOrCreate(['email' => 'youth_admin@church.com'], ['name' => 'Youth Church Admin', 'password' => Hash::make('password123'), 'role' => 'admin', 'church_id' => $youthChurch->id]); $youthAdmin->roles()->sync([Role::findBySlug(Role::ADMIN)->id]); $youthCurate = User::firstOrCreate(['email' => 'youth_curate@church.com'], ['name' => 'Youth Curate Pastor', 'password' => Hash::make('password123'), 'role' => 'curate_pastor', 'church_id' => $youthChurch->id]); $youthCurate->roles()->sync([Role::findBySlug('curate_pastor')->id]); } } }
